import { PrismaClient, AdviceCategory, ContentSource } from '@prisma/client';
const prisma = new PrismaClient();

export async function seedPregnancyAdviceCards() {
  console.log('Seeding pregnancy/newborn advice cards...');
  const cards = [
    { stageKey: 'preg_week_1', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 85, title: 'How Pregnancy Weeks Are Actually Counted', summary: 'Pregnancy dating starts earlier than you might think — here is why week one begins before conception even happens.', content: 'Healthcare providers count pregnancy weeks from the first day of your last menstrual period (LMP), not from conception. This means that during weeks one and two of pregnancy, you have not actually conceived yet — your body is preparing for ovulation. By the time you miss your period and get a positive test, you are already considered about four weeks pregnant. Understanding this dating method helps make sense of pregnancy milestones and due date calculations. If your cycles are irregular, your provider may use an early ultrasound to confirm dating. A full-term pregnancy is 40 weeks from LMP. ACOG defines 37-38 weeks as early term, 39-40 weeks as full term, 41 weeks as late term, and 42+ weeks as postterm — outcomes differ across these windows.', source: 'CLINICAL' as ContentSource, tags: ['pregnancy dating', 'LMP', 'due date', 'gestational age', 'full term'] },
    { stageKey: 'preg_week_2', category: 'DEVELOPMENT' as AdviceCategory, priority: 82, title: 'Ovulation and Your Fertile Window', summary: 'Your body is preparing to release an egg — understanding ovulation timing helps you make sense of your cycle whether you are trying to conceive or not.', content: 'Around week two of your cycle, rising estrogen levels trigger a surge of luteinizing hormone (LH), which signals your ovary to release a mature egg. This is ovulation. The egg survives about 12 to 24 hours after release, but sperm can live in the reproductive tract for up to five days, creating a fertile window of roughly six days each cycle. Signs of approaching ovulation include changes in cervical mucus — it becomes clear, slippery, and stretchy, resembling raw egg whites. Some people also notice mild one-sided pelvic pain called mittelschmerz. Tracking ovulation can be done through ovulation predictor kits, basal body temperature charting, or monitoring cervical mucus changes.', source: 'DEVELOPMENT' as ContentSource, tags: ['ovulation', 'fertile window', 'LH surge', 'cervical mucus', 'conception'] },
    { stageKey: 'preg_week_3', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Conception: The Moment Everything Begins', summary: 'A single sperm meets an egg and sets off a remarkable chain of cell division — your baby is already on the move toward the uterus.', content: 'Within 24 hours of fertilization, the single-celled zygote begins dividing rapidly as it travels through the fallopian tube toward the uterus. By day three, it becomes a morula — a solid ball of about 16 cells. Around day five or six, it transforms into a blastocyst with an inner cell mass that will become the embryo and an outer layer that will form the placenta. The blastocyst hatches from its protective shell and begins the process of implantation into the uterine lining. This entire journey takes about six to ten days from fertilization. At this stage, the developing cells are smaller than the period at the end of this sentence — yet they already contain the complete genetic blueprint for your baby.', source: 'DEVELOPMENT' as ContentSource, tags: ['conception', 'fertilization', 'blastocyst', 'cell division', 'implantation'] },
    { stageKey: 'preg_week_4', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 92, title: 'Implantation: Your Body\'s First Hello', summary: 'The blastocyst burrows into your uterine lining — and your body begins sending the very first pregnancy signals.', content: 'Around the end of week four, the blastocyst completes implantation, embedding itself into the thickened, blood-rich lining of your uterus. Some people experience implantation bleeding — light spotting that is typically pink or brown, not bright red, and much lighter than a period. This is completely normal and nothing to worry about. At this point, the developing placenta starts producing human chorionic gonadotropin (hCG), the hormone detected by pregnancy tests. hCG signals your ovary to continue producing progesterone, which maintains the uterine lining and prevents menstruation. If you take a pregnancy test now, it may or may not show positive depending on your hCG levels and the test sensitivity.', source: 'CLINICAL' as ContentSource, tags: ['implantation', 'hCG', 'spotting', 'early pregnancy signs', 'progesterone'] },
    { stageKey: 'preg_week_4', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 84, title: 'The Two-Week Wait: Finding Calm in Uncertainty', summary: 'The days between ovulation and your expected period can feel emotionally intense — here are gentle strategies to navigate them.', content: 'The two-week wait — the time between ovulation and when you can take a pregnancy test — can be one of the most emotionally charged periods of the conception journey. It is completely normal to feel hyper-aware of every physical sensation, to swing between hope and worry, and to struggle with the uncertainty. Try grounding yourself with gentle activities: prenatal yoga, walking, journaling, or connecting with a trusted friend. Remind yourself that early pregnancy symptoms and premenstrual symptoms are nearly identical — bloating, breast tenderness, and mood changes can occur with both. Whatever you are feeling is valid. Whether you are trying to conceive or this is an unexpected possibility, be kind to yourself during this waiting period.', source: 'DEVELOPMENT' as ContentSource, tags: ['two-week wait', 'emotional health', 'anxiety', 'self-care', 'early pregnancy'] },
    { stageKey: 'preg_week_5', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 95, title: 'You\'re Pregnant! Essential First Steps to Take', summary: 'That positive test is life-changing — here is your checklist for the earliest days of pregnancy.', content: 'First, confirm the pregnancy with your healthcare provider, who may schedule blood work to check hCG levels and your overall health. Start taking a prenatal vitamin with at least 400 micrograms of folic acid right away if you have not already — the neural tube, which becomes the brain and spinal cord, is forming now and folic acid is critical for preventing neural tube defects. Discontinue alcohol, tobacco, and recreational substances immediately, as these can affect early development. Review any prescription medications with your doctor to ensure they are pregnancy-safe. Limit caffeine to about 200 mg per day, or roughly one 12-ounce cup of coffee. Schedule your first prenatal visit, which typically happens between weeks 8 and 10.', source: 'CLINICAL' as ContentSource, tags: ['positive pregnancy test', 'prenatal vitamins', 'folic acid', 'first steps', 'obstetrician'] },
    { stageKey: 'preg_week_5', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 88, title: 'Building Your Baby: Nutrition in the First Weeks', summary: 'What you eat now lays the foundation — here is what your growing embryo needs most.', content: 'During these earliest weeks, your baby is developing the neural tube, heart, and major organ systems — and nutrition plays a starring role. Prioritize folate-rich foods such as dark leafy greens, lentils, asparagus, and fortified grains, in addition to your prenatal vitamin. Iron supports increased blood volume, so include lean meats, beans, and spinach. Calcium and vitamin D are essential for bone development — dairy products, fortified plant milks, and fatty fish are excellent sources. Foods to avoid include raw or undercooked meat and seafood, unpasteurized dairy, high-mercury fish like swordfish and king mackerel, and deli meats unless heated until steaming hot. Morning sickness may make eating challenging — small, frequent meals and bland carbohydrates like crackers or toast can help.', source: 'DEVELOPMENT' as ContentSource, tags: ['prenatal nutrition', 'folate', 'food safety', 'morning sickness', 'vitamins'] },
    { stageKey: 'preg_week_7', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Your Baby at 7 Weeks: A Tiny Heart Beating', summary: 'Though you cannot feel it yet, your embryo is undergoing an astonishing transformation — including a heartbeat visible on ultrasound.', content: 'At seven weeks, your embryo has doubled in size from last week and is now about the size of a blueberry — roughly 10 millimeters from crown to rump. The neural tube has closed, and the brain is developing into three distinct sections: forebrain, midbrain, and hindbrain. Limb buds are elongating, with tiny hand plates beginning to form where fingers will eventually appear. The heart has divided into chambers and is beating at about 150 beats per minute — almost twice as fast as yours — and can often be seen on a transvaginal ultrasound. Facial features are taking shape, with dark spots where eyes will develop and small indentations marking the future ears and nostrils. It is normal not to feel pregnant yet, even though so much is happening inside.', source: 'DEVELOPMENT' as ContentSource, tags: ['embryo development', 'heartbeat', 'neural tube', 'ultrasound', 'brain development'] },
    { stageKey: 'preg_week_8', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 93, title: 'Your First Prenatal Visit: What to Expect', summary: 'The first prenatal appointment is comprehensive — here is a walkthrough so you walk in prepared and confident.', content: 'Your first prenatal visit, typically scheduled between 8 and 10 weeks, is one of the longest appointments of your entire pregnancy. Your provider will take a detailed medical history, including previous pregnancies, chronic conditions, family medical history, and any medications you take. Expect a physical exam including a pelvic exam and Pap smear if you are due for one. Blood work will screen for blood type, Rh factor, anemia, immunity to rubella and varicella, sexually transmitted infections, and other baseline health markers. Your provider will also likely perform a urine test to check for infection, protein, and glucose. This is your opportunity to ask every question you have — write them down beforehand so you do not forget anything in the moment. If you do not understand something, ask for clarification.', source: 'CLINICAL' as ContentSource, tags: ['prenatal visit', 'blood work', 'pelvic exam', 'medical history', 'first trimester'] },
    { stageKey: 'preg_week_8', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 86, title: 'Navigating Morning Sickness: It\'s Not Just Morning', summary: 'Nausea can strike at any time of day — here are evidence-backed strategies to find relief.', content: 'Despite the name, morning sickness can occur any time of day or night, affecting up to 80 percent of pregnant people during the first trimester. The exact cause is not fully understood but is linked to rising hCG and estrogen levels. Small, frequent meals throughout the day help prevent an empty stomach, which can worsen nausea. Bland, starchy foods like crackers, dry toast, rice, and bananas are often better tolerated. Ginger in various forms — tea, chews, or capsules — has good evidence for reducing pregnancy nausea. Vitamin B6 supplements (25 mg every 8 hours) are a first-line treatment recommended by the American College of Obstetricians and Gynecologists. If you cannot keep any food or liquids down, experience weight loss, or feel faint, contact your provider — this may be hyperemesis gravidarum, which requires medical treatment.', source: 'DEVELOPMENT' as ContentSource, tags: ['morning sickness', 'nausea', 'ginger', 'vitamin B6', 'hyperemesis gravidarum'] },
    { stageKey: 'preg_week_10', category: 'DEVELOPMENT' as AdviceCategory, priority: 91, title: 'Goodbye Embryo, Hello Fetus: Week 10 Milestone', summary: 'Your baby officially graduates from embryo to fetus — and all essential organs are now formed.', content: 'Week 10 marks a significant developmental milestone: your developing baby is now called a fetus rather than an embryo. This transition means that all essential organ systems — brain, heart, lungs, kidneys, liver, and digestive tract — have been formed, though they will continue maturing throughout the rest of pregnancy. The fetus is now about 3 centimeters long, roughly the size of a prune or a strawberry. Tiny fingernails and toenails are beginning to form. The tail at the base of the spinal cord has disappeared, and the external ears are moving into their correct positions on the sides of the head. The fetus is already making small movements, though you will not feel them for several more weeks. The most critical period of structural development is now complete, which means the risk of major birth defects decreases significantly from this point forward.', source: 'DEVELOPMENT' as ContentSource, tags: ['fetal development', 'embryonic period', 'organogenesis', 'milestone', 'first trimester'] },
    { stageKey: 'preg_week_10', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 83, title: 'Telling People You\'re Pregnant: Your Choice, Your Timeline', summary: 'Whether to share your news early or wait — there is no single right answer, only what feels right for you.', content: 'Deciding when and how to share pregnancy news is deeply personal. Some people tell close family and friends immediately after a positive test, wanting that support network in place no matter what happens. Others wait until the end of the first trimester when miscarriage risk drops significantly, around week 12 or 13. Both approaches are completely valid. Consider whether you want support through early anxiety or prefer privacy during these vulnerable weeks. When telling your workplace, review your company\'s parental leave policies and consider how this announcement might affect upcoming projects or promotions. Your news, your timeline.', source: 'DEVELOPMENT' as ContentSource, tags: ['sharing pregnancy news', 'first trimester', 'workplace disclosure', 'emotional health', 'partner communication'] },
    { stageKey: 'preg_week_12', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 94, title: 'The NT Scan and First Trimester Screening', summary: 'Between weeks 11 and 13, you have a window for important screening — here is what the nuchal translucency scan involves.', content: 'The nuchal translucency (NT) scan is an ultrasound performed between 11 and 13 weeks of pregnancy that measures the fluid-filled space at the back of the fetus\'s neck. Combined with blood work, this screening assesses the likelihood of chromosomal conditions including Down syndrome (trisomy 21), Edwards syndrome (trisomy 18), and Patau syndrome (trisomy 13). This is a screening test, not a diagnostic test — it tells you whether you are at increased or decreased risk, not a definitive yes or no. The ultrasound is completely safe and usually takes about 20 to 40 minutes. Many parents treasure this scan because it provides the clearest view yet of their baby, who will now look distinctly human with visible arms, legs, and facial profile.', source: 'CLINICAL' as ContentSource, tags: ['NT scan', 'nuchal translucency', 'genetic screening', 'first trimester screening', 'ultrasound'] },
    { stageKey: 'preg_week_12', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 88, title: 'Eating for Two: What That Really Means', summary: 'The old saying is misleading — you are not eating for two adults, and quality matters far more than quantity.', content: 'During the first trimester, you do not need any additional calories beyond your pre-pregnancy intake. The focus should be on nutrient density, not quantity. Even in the second and third trimesters, the added calorie needs are modest: roughly 340 extra calories per day in the second trimester and 450 in the third — equivalent to a sandwich and a piece of fruit, not a second dinner. Protein needs increase to support tissue growth. Omega-3 fatty acids, especially DHA, are critical for fetal brain and eye development from low-mercury fish like salmon and sardines two to three times per week. Iron needs nearly double during pregnancy, and many people benefit from supplementation alongside dietary sources. Listen to your hunger cues rather than rigid rules — your body is remarkably wise about what it needs.', source: 'DEVELOPMENT' as ContentSource, tags: ['prenatal nutrition', 'calories in pregnancy', 'protein', 'omega-3', 'DHA'] },
    { stageKey: 'preg_week_14', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 89, title: 'Welcome to the Second Trimester: What Changes Now', summary: 'Many parents find the second trimester brings renewed energy — and your baby is entering a rapid growth phase.', content: 'The second trimester is often called the honeymoon phase of pregnancy, and for good reason. For many, nausea begins to subside, energy levels rebound, and the risk of miscarriage drops significantly after week 13. Your baby is now about the size of a lemon, measuring approximately 8 to 9 centimeters. The neck is becoming more defined and fine hair called lanugo is beginning to cover the body. Your baby\'s kidneys are producing urine, which is released into the amniotic fluid. If you have been waiting to share your pregnancy news, this is a common time to do so. Take this window of renewed energy to enjoy gentle movement, plan a short babymoon, or tackle the early research you have been putting off.', source: 'DEVELOPMENT' as ContentSource, tags: ['second trimester', 'energy recovery', 'fetal growth', 'lanugo', 'pregnancy milestone'] },
    { stageKey: 'preg_week_16', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Quickening: The First Flutter of Movement', summary: 'Sometime between 16 and 22 weeks, you may feel your baby\'s first movements — a moment you will never forget.', content: 'Quickening is the term for the first time you feel fetal movement, and it is one of the most anticipated milestones of pregnancy. First-time parents typically notice these sensations between 18 and 22 weeks, while those who have been pregnant before may feel them earlier, around 16 to 18 weeks. The initial sensations are subtle — many describe them as flutters, bubbles, popcorn popping, or goldfish swimming. It is easy to mistake early movements for gas or digestive activity. As weeks pass, movements become stronger and more distinct. The position of the placenta matters: an anterior placenta can cushion movements, making them harder to feel early on. Not feeling movement until 22 weeks or later can be completely normal for a first pregnancy. If you have concerns, always check with your provider.', source: 'DEVELOPMENT' as ContentSource, tags: ['quickening', 'fetal movement', 'first kicks', 'anterior placenta', 'second trimester'] },
    { stageKey: 'preg_week_18', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 82, title: 'Body Image and the Changing Pregnant Body', summary: 'Your body is transforming in visible ways — navigating these changes with self-compassion matters for your emotional health.', content: 'Between weeks 16 and 20, many pregnant people find their belly becomes noticeably and undeniably pregnant-looking. This transition can bring a complex mix of emotions — joy at visible proof of your growing baby, anxiety about weight gain, discomfort with how clothes fit, or sadness about losing a body shape you were comfortable with. All of these feelings are normal and common. Weight gain recommendations vary based on pre-pregnancy BMI, ranging from about 11 to 18 kilograms for those in the normal weight range. Remember that weight gain includes not just the baby but the placenta, amniotic fluid, increased blood volume, enlarged uterus, and breast tissue — your body is doing an extraordinary job. Maternity clothes and belly bands can help you feel more comfortable and confident.', source: 'DEVELOPMENT' as ContentSource, tags: ['body image', 'weight gain', 'maternity clothes', 'perinatal mental health', 'self-compassion'] },
    { stageKey: 'preg_week_20', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 96, title: 'The Anatomy Scan: Your 20-Week Ultrasound', summary: 'This detailed scan examines your baby from head to toe — it is the most comprehensive ultrasound of your pregnancy.', content: 'The mid-pregnancy ultrasound, also called the anatomy scan or level 2 ultrasound, is typically performed between 18 and 22 weeks. It is the most detailed scan of your pregnancy, systematically examining your baby\'s brain, face, spine, heart, lungs, abdominal organs, kidneys, limbs, and placenta. The sonographer measures your baby\'s head circumference, abdominal circumference, and femur length to confirm growth is on track. The scan also checks amniotic fluid levels, placental position, and cervical length. Many parents find out their baby\'s sex at this scan if they choose to and if the position allows a clear view. The examination takes about 30 to 60 minutes depending on your baby\'s cooperation.', source: 'CLINICAL' as ContentSource, tags: ['anatomy scan', '20-week ultrasound', 'fetal anatomy', 'placenta', 'amniotic fluid'] },
    { stageKey: 'preg_week_20', category: 'PLAY_ACTIVITIES' as AdviceCategory, priority: 80, title: 'Bonding with Your Baby Before Birth', summary: 'Your baby can hear you now — simple daily practices can begin building your connection months before you meet.', content: 'By week 20, your baby\'s hearing has developed enough to detect sounds from outside the womb, including your voice, your heartbeat, and even music. Research suggests that newborns recognize and are soothed by voices they heard frequently during pregnancy. Talking, reading aloud, or singing to your baby are simple yet powerful bonding practices. Your partner or other family members can participate too, building their own early connection. Some parents find it meaningful to play a particular song during pregnancy and then use it after birth as a calming cue. Bonding does not always happen instantly or automatically for every parent — if you feel disconnected, that is normal and does not predict your relationship with your child.', source: 'DEVELOPMENT' as ContentSource, tags: ['prenatal bonding', 'fetal hearing', 'baby\'s hearing', 'singing to baby', 'parent-child connection'] },
    { stageKey: 'preg_week_22', category: 'DEVELOPMENT' as AdviceCategory, priority: 88, title: 'Preterm Labor: Knowing the Warning Signs', summary: 'Understanding the signs of preterm labor empowers you to act quickly if needed — knowledge is your best tool.', content: 'Preterm labor is labor that begins before 37 weeks of pregnancy. Knowing the signs means you can seek prompt medical attention, which can sometimes allow interventions to delay delivery or prepare your baby for an early arrival. Key warning signs include regular contractions or tightening that occur more than four to five times in an hour and do not go away with rest, menstrual-like cramping that persists, dull low backache that is different from your usual pregnancy back pain, and pelvic pressure that feels like the baby is pushing down. Changes in vaginal discharge — especially if it becomes watery, mucus-like, or bloody — warrant immediate attention. A sudden gush or steady trickle of fluid could mean your water has broken. For most pregnant people, preterm labor does not happen, but knowing the signs is part of being an informed and prepared parent.', source: 'GENERAL' as ContentSource, tags: ['preterm labor', 'warning signs', 'contractions', 'premature birth', 'emergency preparedness'] },
    { stageKey: 'preg_week_24', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 94, title: 'Glucose Screening: Understanding the Test', summary: 'The glucose challenge test checks for gestational diabetes — here is what the test involves and why it matters for you and your baby.', content: 'Between 24 and 28 weeks, nearly all pregnant people are screened for gestational diabetes, a condition where pregnancy hormones interfere with insulin function, leading to elevated blood sugar. The standard one-hour glucose challenge test involves drinking a sweet glucose solution and having your blood drawn exactly one hour later — no fasting is typically required. If your result exceeds the threshold, usually 130 to 140 mg/dL, you will be asked to return for a three-hour glucose tolerance test, which does require fasting. Gestational diabetes affects approximately 6 to 9 percent of pregnancies and, when managed, outcomes are excellent. Untreated, it can lead to excessive fetal growth, birth complications, and newborn blood sugar issues. Risk factors include being overweight, having a family history of diabetes, being over age 25, and certain ethnic backgrounds — but anyone can develop it.', source: 'CLINICAL' as ContentSource, tags: ['gestational diabetes', 'glucose screening', 'blood sugar', 'GDM', 'glucose tolerance test'] },
    { stageKey: 'preg_week_24', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 86, title: 'Managing Gestational Diabetes Through Diet', summary: 'If you receive a GDM diagnosis, nutrition becomes your most powerful management tool — and it is entirely manageable.', content: 'A diagnosis of gestational diabetes can feel overwhelming, but with the right nutritional approach, most people manage it successfully through diet and lifestyle alone. The key principle is balancing carbohydrates with protein and healthy fats at every meal to prevent blood sugar spikes. Focus on complex carbohydrates with fiber — whole grains, legumes, vegetables — rather than refined carbohydrates and sugars. Eating smaller, more frequent meals throughout the day helps maintain steady blood sugar. Pairing fruits with a protein source like cheese or nuts moderates the blood sugar impact. Regular gentle exercise, especially walking after meals, significantly improves glucose control. This is not your fault — pregnancy hormones create insulin resistance in everyone, and for some people it simply crosses the threshold into GDM.', source: 'DEVELOPMENT' as ContentSource, tags: ['gestational diabetes', 'nutrition', 'blood sugar management', 'carbohydrates', 'GDM diet'] },
    { stageKey: 'preg_week_26', category: 'SLEEP' as AdviceCategory, priority: 84, title: 'Sleeping Well When Sleep Gets Harder', summary: 'As your belly grows, finding a comfortable sleeping position becomes a real challenge — here are strategies that actually help.', content: 'By the second half of pregnancy, sleeping comfortably can feel like a puzzle with no solution. The recommended position is sleeping on your side — ideally the left side — which optimizes blood flow to the placenta and reduces pressure on the vena cava. A pregnancy pillow or a combination of regular pillows can transform your sleep: place one between your knees to align your hips, one under your belly for support, and another behind your back to prevent rolling onto your back. If you wake up on your back, do not panic — simply roll back onto your side. Heartburn, frequent urination, and restless legs can all disrupt sleep. For heartburn, avoid eating within two to three hours of bedtime and elevate your head. Staying hydrated during the day but tapering fluids in the evening helps with nighttime bathroom trips.', source: 'DEVELOPMENT' as ContentSource, tags: ['pregnancy sleep', 'side sleeping', 'pregnancy pillow', 'heartburn', 'restless legs'] },
    { stageKey: 'preg_week_28', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Welcome to the Third Trimester: The Final Stretch', summary: 'You have entered the home stretch — here is what the third trimester brings and how to prepare for the weeks ahead.', content: 'Week 28 marks the official start of the third trimester. Your baby now has a greater than 90 percent chance of survival if born prematurely, though the goal remains full term. From this point forward, prenatal appointments become more frequent — typically every two weeks until week 36, then weekly until delivery. Your provider will start monitoring your baby\'s position and growth more closely. Braxton Hicks contractions — practice contractions that feel like tightening across your abdomen — may become more noticeable; they are irregular, usually painless, and do not cause cervical change. Your baby is now opening and closing their eyes, responding to light, and regularly practicing breathing movements with their developing lungs. You may feel more fatigued as carrying extra weight takes its toll.', source: 'DEVELOPMENT' as ContentSource, tags: ['third trimester', 'Braxton Hicks', 'prenatal appointments', 'fetal viability', 'childbirth education'] },
    { stageKey: 'preg_week_28', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 84, title: 'Preparing Emotionally for Birth and Parenthood', summary: 'Beyond the practical preparations, your emotional readiness matters — here is how to nurture your mental health in the third trimester.', content: 'As birth approaches, it is completely normal to experience a range of emotions: excitement, anxiety, fear, joy, and everything in between. Taking a childbirth education class can significantly reduce fear by replacing unknowns with knowledge. Writing a birth preferences document helps you think through your options and communicate them to your care team, while holding those preferences loosely since birth is unpredictable. Consider starting therapy now if you have a history of anxiety, depression, or trauma — establishing a therapeutic relationship before the postpartum period is easier than starting from scratch while caring for a newborn. Practice relaxation techniques, visualization, or meditation now so they feel familiar when you need them in labor.', source: 'DEVELOPMENT' as ContentSource, tags: ['emotional preparation', 'birth anxiety', 'childbirth education', 'perinatal mental health', 'birth preferences'] },
    { stageKey: 'preg_week_30', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 87, title: 'Choosing a Pediatrician: Your Baby\'s First Doctor', summary: 'You will choose your baby\'s healthcare provider before birth — here is how to find the right fit for your family.', content: 'Selecting a pediatrician or family medicine provider for your baby is an important decision best made before delivery, since the provider will examine your newborn within 24 hours of birth. Start by gathering recommendations from your obstetrician, friends, family, and local parenting groups. Consider practical factors: location and proximity to your home, office hours including evenings and weekends, whether the practice has multiple providers or a single doctor, and which hospitals they have privileges at. Most pediatric practices offer free prenatal meet-and-greet visits — take advantage of these. Prepare questions about their philosophy on topics important to you: breastfeeding support, vaccination schedule, antibiotic use, sleep guidance, and how they handle after-hours concerns. Pay attention to how you feel during the visit — you want a provider who listens well, communicates clearly, and makes you feel respected.', source: 'GENERAL' as ContentSource, tags: ['pediatrician', 'newborn care', 'prenatal preparation', 'healthcare provider', 'baby doctor'] },
    { stageKey: 'preg_week_32', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Your Baby at 32 Weeks: Almost Ready for the World', summary: 'Your baby is practicing essential skills for life outside the womb — and packing on adorable baby fat.', content: 'At 32 weeks, your baby weighs roughly 1.7 to 1.8 kilograms (3.75 to 4 pounds) and measures about 42 centimeters (16.5 inches) from head to toe. The skeleton is fully formed but the bones remain soft and flexible for the journey through the birth canal. Your baby is now practicing rhythmic breathing movements, though the lungs are not yet fully mature — they are producing surfactant, the substance that keeps the air sacs from collapsing after birth. Baby fat is accumulating under the skin, smoothing out wrinkles and helping with temperature regulation after birth. Your baby may now be settling into a head-down position in preparation for delivery. The five senses are all functioning: your baby can see light filtering through your abdomen, hear your voice clearly, taste the amniotic fluid, and respond to touch and sound.', source: 'DEVELOPMENT' as ContentSource, tags: ['fetal development', '32 weeks', 'surfactant', 'kick counting', 'baby position'] },
    { stageKey: 'preg_week_32', category: 'SLEEP' as AdviceCategory, priority: 83, title: 'Kick Counting: A Daily Check-In with Your Baby', summary: 'Monitoring your baby\'s movement patterns is one of the most effective ways to check on fetal well-being at home.', content: 'Kick counting — more accurately called fetal movement counting — is a simple, free way to monitor your baby\'s well-being in the third trimester. Find a consistent time each day when your baby is typically active, sit or lie on your side in a quiet place, and count each distinct movement — kicks, rolls, stretches, and jabs all count, just not hiccups. The goal is typically 10 movements within two hours. Most babies achieve 10 movements in well under 30 minutes. Count at approximately the same time each day to establish your baby\'s normal pattern. A significant decrease or change in your baby\'s usual pattern of movement should prompt a call to your provider — never wait until the next day. Trust your instincts; you know your baby\'s patterns better than anyone.', source: 'CLINICAL' as ContentSource, tags: ['kick counting', 'fetal movement', 'stillbirth prevention', 'third trimester', 'fetal monitoring'] },
    { stageKey: 'preg_week_34', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 91, title: 'Group B Strep: The Test That Protects Your Baby', summary: 'Around week 36, you will be screened for Group B Streptococcus — a routine test with a simple intervention that saves newborn lives.', content: 'Group B Streptococcus (GBS) is a common bacterium carried by approximately 25 percent of healthy adults in their gastrointestinal and genital tracts, usually without any symptoms. However, GBS can be transmitted to the baby during vaginal delivery and, in rare cases, can cause serious infections including pneumonia, sepsis, and meningitis in newborns. The screening involves a simple swab of the vagina and rectum, typically performed between weeks 36 and 37. If you test positive, the intervention is straightforward: you will receive intravenous antibiotics, usually penicillin, during labor, which reduces the risk of newborn GBS infection by over 80 percent. Testing positive is not a sign that you did anything wrong — it is simply part of your normal bacterial flora. Make sure your birth team knows your GBS status when you arrive in labor.', source: 'CLINICAL' as ContentSource, tags: ['Group B Strep', 'GBS screening', 'newborn infection', 'antibiotics in labor', 'third trimester'] },
    { stageKey: 'preg_week_34', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 86, title: 'Your Postpartum Plan: Preparing for the Fourth Trimester', summary: 'Everyone plans for birth — but planning for after the baby arrives is just as essential and often overlooked.', content: 'The postpartum period, sometimes called the fourth trimester, is a time of immense physical recovery, emotional adjustment, and learning to care for a newborn — all while severely sleep-deprived. Creating a postpartum plan now, while you still have mental bandwidth, is one of the best gifts you can give your future self. Stock your freezer with nutritious meals. Identify your support network in advance — a partner, family member, postpartum doula, or trusted friend who can help with practical tasks. Set up nursing and diaper-changing stations on every floor of your home. Learn about the baby blues versus postpartum depression and anxiety, and make sure your partner or support person knows the warning signs too. Discuss with your partner how you will handle overnight feedings and household responsibilities.', source: 'DEVELOPMENT' as ContentSource, tags: ['postpartum planning', 'fourth trimester', 'meal preparation', 'support network', 'postpartum depression'] },
    { stageKey: 'preg_week_36', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 94, title: 'Packing Your Hospital Bag: The Complete Checklist', summary: 'Labor can start unexpectedly — having your bag ready by 36 weeks means one less thing to think about when it does.', content: 'By 36 weeks, your hospital or birth center bag should be packed and waiting by the door. Essentials include your identification, insurance card, and any hospital registration paperwork. For labor: comfortable loose clothing, non-skid slippers, lip balm, hair ties, a massage tool, a Bluetooth speaker for music, snacks for your support person, and a long phone charger. For postpartum recovery: nursing bras, high-waisted comfortable underwear, a going-home outfit that accommodates a postpartum belly, and toiletries. For your baby: a going-home outfit in newborn and 0-3 month sizes, a car seat properly installed in your vehicle, and weather-appropriate blankets. Do not forget items for your support person: change of clothes, toiletries, snacks, and any medications they take.', source: 'DEVELOPMENT' as ContentSource, tags: ['hospital bag', 'labor preparation', 'birth center', 'packing checklist', 'going-home outfit'] },
    { stageKey: 'preg_week_36', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 87, title: 'Colostrum: Your Baby\'s First Superfood', summary: 'Before your milk comes in, your body produces liquid gold — colostrum is perfectly designed for your newborn\'s first feeds.', content: 'Colostrum is the thick, yellowish, nutrient-dense first milk your breasts produce during late pregnancy and the first few days after birth. Sometimes called liquid gold, it is packed with antibodies, particularly immunoglobulin A, which coats your baby\'s intestines and provides their first immune protection. Colostrum is perfectly portioned — newborns\' stomachs are the size of a marble at birth, holding only 5 to 7 milliliters (about a teaspoon) per feed, and colostrum is so concentrated that this small amount is exactly what they need. It acts as a gentle laxative, helping your baby pass their first stool called meconium, which in turn helps reduce the risk of jaundice. Some parents choose to express and store colostrum antenatally starting around week 36 to 37 — discuss this with your provider first.', source: 'DEVELOPMENT' as ContentSource, tags: ['colostrum', 'first milk', 'newborn feeding', 'antibodies', 'breastfeeding'] },
    { stageKey: 'preg_week_38', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 96, title: 'Signs of Labor: Knowing When It\'s Really Time', summary: 'Distinguish between early signs, false labor, and the real thing — so you know when to head to the hospital.', content: 'Recognizing true labor prevents both unnecessary trips to the hospital and dangerous delays. True labor contractions follow a pattern: they come at regular intervals, get progressively closer together, and grow stronger and longer over time. They do not go away with rest, hydration, or position changes. Unlike Braxton Hicks, true labor contractions typically start in the back and wrap around to the front. The 5-1-1 rule is a helpful guideline: contractions coming every 5 minutes, lasting at least 1 minute, for at least 1 hour — but always follow your provider\'s specific guidance. If your water breaks, note the time, color, and odor of the fluid — it should be clear and odorless. Green or brown fluid may indicate meconium and requires immediate attention.', source: 'CLINICAL' as ContentSource, tags: ['signs of labor', 'contractions', '5-1-1 rule', 'water breaking', 'mucus plug'] },
    { stageKey: 'preg_week_38', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 85, title: 'Birth Preferences: Advocacy, Flexibility, and Communication', summary: 'A birth preferences document is a communication tool, not a contract — here is how to create one that truly serves you.', content: 'A birth preferences plan is a written document that communicates your hopes and preferences to your care team. It is most effective when approached as a tool for dialogue, not a rigid script — birth is unpredictable, and flexibility is essential. Include your preferences for labor environment, pain management options, labor positions, and your preferences for interventions. For postpartum, include preferences for immediate skin-to-skin contact, delayed cord clamping, newborn procedures, feeding intentions, and rooming-in. Keep it to one page, use clear bullet points, and write in a collaborative tone. Share it with your provider before labor and review it together. Bring multiple copies to the hospital. The most important preference is that you and your baby are safe and healthy — everything else is secondary.', source: 'GENERAL' as ContentSource, tags: ['birth plan', 'birth preferences', 'advocacy', 'pain management', 'communication'] },
    { stageKey: 'preg_week_40', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 96, title: 'Post-Dates: When Your Due Date Comes and Goes', summary: 'Only about 5 percent of babies arrive on their due date — here is what happens when pregnancy extends beyond 40 weeks.', content: 'Reaching or passing your due date without going into labor is extremely common — about half of first-time parents deliver after 40 weeks. As long as you and your baby are healthy, this is usually not a cause for concern, just for extra monitoring. Your provider will likely schedule more frequent visits including non-stress tests to monitor your baby\'s heart rate and movement, and ultrasounds to check amniotic fluid levels. If you reach 41 weeks, your provider will likely discuss induction of labor, as the risks of stillbirth and complications increase slightly after this point, while induction at 41 weeks has been shown to reduce these risks without increasing the cesarean rate. Membrane sweeping may be offered starting around 38 to 40 weeks — it releases natural prostaglandins and can help encourage labor to start spontaneously.', source: 'CLINICAL' as ContentSource, tags: ['post-dates', 'overdue', 'due date', 'induction', 'non-stress test'] },
    { stageKey: 'preg_week_40', category: 'SLEEP' as AdviceCategory, priority: 87, title: 'Newborn Sleep: What to Actually Expect', summary: 'Newborn sleep looks nothing like adult sleep — understanding what is normal helps you set realistic expectations from day one.', content: 'Newborns sleep approximately 14 to 17 hours out of every 24, but — and this is the crucial part — in very short stretches of 2 to 4 hours at a time, around the clock. This is biologically normal and driven by their tiny stomach capacity and need to feed frequently. Newborns do not distinguish between day and night for the first several weeks. They also spend about 50 percent of their sleep time in REM (active) sleep, during which they may twitch, make noises, smile, and breathe irregularly — this is completely normal and important for brain development. Safe sleep guidelines are critical: always place your baby on their back to sleep, on a firm flat surface with a fitted sheet only, in your room but not your bed, with no blankets, pillows, bumpers, or stuffed animals. Room-sharing for at least the first 6 months is recommended by the American Academy of Pediatrics.', source: 'DEVELOPMENT' as ContentSource, tags: ['newborn sleep', 'SIDS prevention', 'safe sleep', 'REM sleep', 'room-sharing'] },
    { stageKey: 'born_week_4', category: 'DEVELOPMENT' as AdviceCategory, priority: 90, title: 'Week 4: The First Growth Spurt Arrives', summary: 'Around four weeks, many babies hit their first growth spurt — expect increased cluster feeding and fussiness, it is all normal.', content: 'Around 3 to 4 weeks of age, many newborns go through their first significant developmental growth spurt. You may notice your baby wanting to nurse or feed much more frequently than before — sometimes every hour — and being fussier and harder to settle than usual. This is called cluster feeding and it is your baby\'s brilliant biological strategy to increase your milk supply to meet their growing needs. The growth spurt typically lasts a few days, after which feeding patterns usually settle into a new normal. Your baby\'s alert periods may lengthen, and you may notice them studying faces more intently or tracking objects briefly with their eyes. A heads-up: the Period of PURPLE Crying, a normal phase of increased crying that peaks around 6 weeks, may be approaching. Never shake a baby — if you feel overwhelmed, put the baby in a safe place and step away for a few minutes.', source: 'DEVELOPMENT' as ContentSource, tags: ['growth spurt', 'cluster feeding', 'newborn development', 'PURPLE crying', 'witching hour'] },
    { stageKey: 'born_week_4', category: 'PARENT_WELLBEING' as AdviceCategory, priority: 88, title: 'The First Month: Recovering, Surviving, and Finding Your Feet', summary: 'A month in, you are still in the thick of the newborn haze — here is a compassionate check-in on your recovery and mental health.', content: 'By week four postpartum, you may feel pressure to have things figured out — please know that you are still very much in the early days of recovery and adjustment. Your physical healing is ongoing: perineal soreness and lochia may still be present, and a cesarean incision continues to heal internally for weeks. Sleep deprivation is cumulative and real — it affects mood, cognition, and patience. The baby blues — mood swings, tearfulness, irritability — typically onset days 2-5 postpartum, peak around days 3-5, and resolve by 2 weeks. If feelings of sadness, anxiety, hopelessness, or detachment persist beyond two weeks or worsen, this could be postpartum depression or anxiety and is absolutely treatable. Accept help when it is offered. Lower the bar on everything except keeping yourself and your baby fed, safe, and rested.', source: 'DEVELOPMENT' as ContentSource, tags: ['postpartum recovery', 'baby blues', 'postpartum depression', 'fourth trimester', 'self-care'] },
    { stageKey: 'born_week_6', category: 'GROWTH_HEALTH' as AdviceCategory, priority: 95, title: 'The 6-Week Checkup and Your Baby\'s First Vaccines', summary: 'At six weeks, both you and your baby have important checkups — including the first round of immunizations.', content: 'The six-week mark brings important healthcare visits for both parent and baby. Your postpartum checkup assesses your physical recovery: your provider will check your cesarean incision or perineal healing, uterine involution, discuss contraception if desired, and screen for postpartum depression and anxiety. For your baby, the 6- to 8-week visit typically includes the first set of routine vaccinations: DTaP (diphtheria, tetanus, pertussis), Hib, polio, pneumococcal, rotavirus, and the second dose of Hepatitis B, depending on your country\'s schedule. These vaccines protect against serious and potentially life-threatening diseases. Vaccines can cause temporary fussiness, low-grade fever, and soreness at the injection site. You can comfort your baby with feeding, cuddling, and if recommended by your provider, infant acetaminophen.', source: 'CLINICAL' as ContentSource, tags: ['vaccines', 'immunization', 'postpartum checkup', 'DTaP', 'infant health'] },
    { stageKey: 'born_week_6', category: 'DEVELOPMENT' as AdviceCategory, priority: 92, title: 'The Social Smile: Your Baby\'s First Real Communication', summary: 'Sometime around six weeks, your baby will smile at you intentionally — not gas, not a reflex, but a genuine social smile that changes everything.', content: 'Around 6 to 8 weeks, one of the most magical developmental milestones occurs: the social smile. Unlike the reflexive smiles newborns make during sleep or when passing gas, the social smile is a deliberate response to you — your face, your voice, your presence. This is your baby\'s first true social interaction and their way of communicating connection. Encourage social smiling by holding your baby 20 to 30 centimeters from your face — newborns see best at this distance — making eye contact, using an animated voice, and smiling broadly. Do not worry if it happens a bit later — the normal range extends to about 12 weeks. If your baby does not show a social smile by 3 months, mention it to your pediatrician. For most parents, that first genuine smile makes all the sleepless nights feel worth it.', source: 'DEVELOPMENT' as ContentSource, tags: ['social smile', 'developmental milestone', 'baby communication', 'social development', '6 weeks'] },
    { stageKey: 'born_week_12', category: 'DEVELOPMENT' as AdviceCategory, priority: 91, title: 'The End of the Fourth Trimester: Your Baby Emerges', summary: 'At 12 weeks, your newborn is transitioning into infancy — less fragile, more interactive, and starting to find a rhythm.', content: 'Week 12 marks the traditional end of the fourth trimester — the three-month period when your baby is adjusting to life outside the womb and you are adjusting to life as a parent. You will likely notice a significant shift: your baby is more alert for longer stretches, their neck strength is improving, and they may be beginning to bat at objects and bring hands to midline. Fussiness that peaked around 6 to 8 weeks often begins to subside. Sleep patterns may begin to consolidate, with slightly longer stretches at night. Your baby is now producing their own melatonin and beginning to develop a circadian rhythm. This is a good time to start establishing gentle routines — consistent bedtime rituals like a warm bath, feeding, and a lullaby can signal that nighttime is for sleep. Your baby can now recognize familiar people and may begin to show preferences for primary caregivers.', source: 'DEVELOPMENT' as ContentSource, tags: ['fourth trimester', '12 weeks', 'baby development', 'circadian rhythm', 'emerging routine'] },
    { stageKey: 'born_week_12', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 89, title: 'Breastfeeding at 12 Weeks: Supply Regulation and New Normals', summary: 'Around 12 weeks, your milk supply shifts from hormone-driven to demand-driven — here is what this transition means for you and your baby.', content: 'Around 12 weeks postpartum, a significant physiological shift occurs in lactation: your milk supply transitions from being primarily hormone-driven (prolactin) to being demand-driven, also called autocrine control. This means your breasts may feel softer and less engorged than in the early weeks — this is normal and does not indicate low supply. Your baby has likely become a more efficient feeder; nursing sessions may shorten from 30 to 45 minutes down to 10 to 15 minutes as they get stronger and more skilled. Cluster feeding may return periodically during growth spurts to increase supply. Some parents experience a nursing strike around this age — this is usually temporary and related to increased distractibility. If you have concerns about supply, a lactation consultant can provide invaluable hands-on guidance. For formula-feeding parents, 12 weeks is when many babies begin to stretch feeds slightly.', source: 'DEVELOPMENT' as ContentSource, tags: ['breastfeeding', 'milk supply', 'lactation', 'feeding rhythm', 'nursing strike'] },
    { stageKey: 'born_week_0', category: 'NUTRITION_FEEDING' as AdviceCategory, priority: 95, title: 'Vitamin D Supplementation for Breastfed Babies', summary: 'The AAP recommends 400 IU of vitamin D daily starting in the first few days of life for all breastfed and partially breastfed infants.', content: 'Breast milk contains very little vitamin D, regardless of the parent\'s intake or sun exposure. The American Academy of Pediatrics recommends 400 IU (international units) of vitamin D drops daily for all breastfed and partially breastfed infants, beginning in the first few days of life and continuing until the child is consuming at least 1 liter (about 32 ounces) of vitamin D-fortified formula or whole milk per day. Most infant vitamin D drops come in formulations where one drop equals 400 IU — making daily supplementation simple. Formula-fed infants taking less than 32 ounces per day also need supplementation. Vitamin D is critical for calcium absorption, bone development, and immune function. Deficiency can lead to rickets, a softening and weakening of bones that is entirely preventable with adequate intake.', source: 'CLINICAL' as ContentSource, tags: ['vitamin D', 'supplementation', 'breastfeeding', 'rickets prevention', 'AAP guidelines'] },
  ];
  for (const card of cards) {
    await prisma.expertAdviceCard.upsert({
      where: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}` },
      update: card, create: { id: `seed_advice_${card.stageKey}_${card.title.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30)}`, ...card },
    });
  }
  console.log(`Seeded ${cards.length} pregnancy/newborn advice cards`);
}
